void ft_swap(int *a, int *b)
{
    int tmp;
    tmp = *a;
    *a = *b;
    *b = tmp;
}

void ft_div_mod(int a, int b, int *div, int *mod)
{
    *div = a / b;
    *mod = a % b;
}

void ft_ultimate_div_mod(int *a, int *b)
{
    int tmp;
    tmp = *a / *b;
    *b = *a % *b;
    *a = tmp;
}

#include <unistd.h>
void ft_putstr(char *str)
{
    int i;
    i = 0;
    while (str[i])
        write(1, &str[i++], 1);
}

int ft_strlen(char *str)
{
    int i;
    i = 0;
    while (str[i])
        i++;
    return (i);
}

void ft_rev_int_tab(int *tab, int size)
{
    int i; int j; int tmp;
    i = 0; j = size - 1;
    while (i < j) {
        tmp = tab[i];
        tab[i] = tab[j];
        tab[j] = tmp;
        i++; j--;
    }
}

